1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	  yearsWithMHPCO?: number;
11	  firstInsurance?: boolean;
12	  followUp?: boolean;
13	}
14	
15	export interface QuoteResult {
16	  premium: number;
17	}
18	
19	const PROCESSING_FEE = 5;
20	const DEFAULT_BASE_PREMIUM = 100;
21	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	
32	function basePremiumFor(item: Item): number {
33	  const base = BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
34	  const highEnchantmentSurcharge =
35	    item.enchantment === 5 ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
36	  const curseSurcharge = item.cursed ? CURSE_SURCHARGE_RATE : 0;
37	  return base * (1 + highEnchantmentSurcharge + curseSurcharge);
38	}
39	
40	const BLOCK_SIZE = 3;
41	const BLOCK_PREMIUM = 60;
42	
43	const LOYALTY_DISCOUNT_RATE = 0.2;
44	const LOYALTY_MIN_YEARS = 2;
45	
46	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
47	
48	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
49	
50	function applyLoyaltyDiscount(
51	  basePremium: number,
52	  yearsWithMHPCO: number | undefined,
53	): number {
54	  const qualifies =
55	    yearsWithMHPCO !== undefined && yearsWithMHPCO >= LOYALTY_MIN_YEARS;
56	  return qualifies ? basePremium * (1 - LOYALTY_DISCOUNT_RATE) : basePremium;
57	}
58	
59	function groupByType(items: Item[]): Map<string, Item[]> {
60	  const groups = new Map<string, Item[]>();
61	  for (const item of items) {
62	    const group = groups.get(item.type) ?? [];
63	    group.push(item);
64	    groups.set(item.type, group);
65	  }
66	  return groups;
67	}
68	
69	function basePremiumForGroup(group: Item[]): number {
70	  if (group.length === BLOCK_SIZE) {
71	    return BLOCK_PREMIUM;
72	  }
73	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
74	}
75	
76	export function quote(input: QuoteInput): QuoteResult {
77	  const groups = [...groupByType(input.items).values()];
78	  const basePremium = groups.reduce(
79	    (sum, group) => sum + basePremiumForGroup(group),
80	    0,
81	  );
82	
83	  const firstInsuranceSurcharge = input.firstInsurance
84	    ? basePremium * FIRST_INSURANCE_SURCHARGE_RATE
85	    : 0;
86	
87	  const followUpDiscount = input.followUp
88	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
89	    : 0;
90	
91	  const policyBase = applyLoyaltyDiscount(basePremium, input.yearsWithMHPCO);
92	
93	  return {
94	    premium:
95	      policyBase + firstInsuranceSurcharge - followUpDiscount + PROCESSING_FEE,
96	  };
97	}
